INSERT INTO plants (name, watering_recommendations, lighting_recommendations, repotting_info, toxicity_info, additional_features) VALUES 
('Монстера деликатесная (Monstera deliciosa)', 'Полив умеренный. Давать верхнему слою почвы (около 3-5 см) просохнуть между поливами.', 'Яркий рассеянный свет. Может расти в полутени, но рост замедлится, а листья будут без прорезей.', 'Пересаживать молодые растения каждую весну, взрослые — раз в 2-3 года.', 'Токсична для кошек, собак и людей при проглатывании (вызывает раздражение слизистых).', 'Нуждается в опоре (кокосовая палка). Воздушные корни не обрезать, а направлять в почву.'),
('Спатифиллум (Spathiphyllum)', 'Обильный полив теплой отстоянной водой. Растение само "подскажет" о жажде, слегка опустив листья.', 'Теневыносливо, но для цветения нужен яркий рассеянный свет без прямых солнечных лучей.', 'Пересадка весной по мере заполнения горшка корнями (обычно раз в год).', 'Слаботоксично, сок может вызывать раздражение.', 'Отлично очищает воздух, любит частые опрыскивания.'),
('Замиокулькас (Zamioculcas)', 'Очень редкий полив (1-2 раза в месяц). Почва должна полностью просыхать до самого дна.', 'Хорошо растет как в тени, так и на ярком солнце. Универсален.', 'Редко, только когда клубни начинают деформировать пластиковый горшок (раз в 3-4 года).', 'Токсично при попадании внутрь организма.', 'Не переносит переувлажнения и застоя воды. Идеально для новичков.'),
('Фикус каучуконосный (Ficus elastica)', 'Умеренный полив после просыхания верхней трети грунта. Зимой полив сокращают.', 'Яркий рассеянный свет. Пестролистным сортам нужно больше света.', 'Каждые 1-2 года весной. Для старых крупных экземпляров — только замена верхнего слоя грунта.', 'Сок ядовит, может вызывать аллергические реакции и дерматит.', 'Нужно регулярно протирать крупные листья влажной губкой от пыли.'),
('Сансевиерия (Sansevieria)', 'Скудный полив. Летом раз в 2-3 недели, зимой можно раз в 1-2 месяца. Главное не заливать.', 'Справится с любой освещенностью от глубокой тени до прямого южного солнца.', 'Только когда корни разорвут горшок. Предпочитает тесные емкости.', 'Токсична для питомцев (вызывает расстройство ЖКТ).', 'Один из лучших очистителей воздуха, выделяет кислород даже ночью.'),
('Эпипремнум золотистый (Epipremnum aureum)', 'Полив после просыхания верхнего слоя земли. Терпим к легким засухам.', 'Любой свет, кроме прямых палящих лучей. В тени пестрота листьев может исчезнуть.', 'Раз в год весной в горшок чуть большего размера.', 'Умеренно токсично для домашних животных.', 'Очень быстро растет, легко черенкуется и может выращиваться как ампельное или на опоре.'),
('Алоэ вера (Aloe vera)', 'Редкий полив. Летом по мере полного просыхания грунта, зимой практически не поливать.', 'Прямое солнце или очень яркий свет. Идеально для южного окна.', 'Молодые — ежегодно, взрослые — раз в 2-3 года. Нужен дренаж.', 'Слаботоксично для животных (вызывает диарею).', 'Сок имеет лечебные свойства, заживляет мелкие порезы и ожоги.'),
('Хлорофитум хохлатый (Chlorophytum comosum)', 'Обильный полив летом, умеренный зимой. На концах листьев сохнут кончики при недостатке влаги.', 'Любит яркий рассеянный свет, но хорошо адаптируется к полутени.', 'Очень часто, так как имеет мощную корневую систему, быстро заполняющую горшок.', 'Абсолютно безопасно для кошек, собак и людей.', 'Считается лучшим зеленым фильтром от формальдегидов в помещениях.'),
('Драцена маргината (Dracaena marginata)', 'Полив после просыхания грунта наполовину. Чувствительна к застою влаги.', 'Яркий непрямой свет. Терпима к легкому притенению.', 'Каждые 2-3 года. Требуется высокий и узкий горшок из-за строения корней.', 'Токсична для кошек и собак.', 'Реагирует на сухой воздух коричневыми кончиками листьев, полезно опрыскивать.'),
('Крассула (Толстянка / Денежное дерево)', 'Как и все суккуленты — редкий полив. Почва должна высыхать полностью.', 'Максимально яркий свет, желательны прямые солнечные лучи.', 'Раз в 2 года в широкий и неглубокий тяжелый горшок (керамика), чтобы растение не перевернулось.', 'Токсично для питомцев.', 'Считается символом финансового благополучия. Легко формируется в бонсай.'),
('Маранта (Maranta leuconeura)', 'Грунт должен быть всегда слегка влажным, но без болота. Любит влажность.', 'Полутень или рассеянный свет. На ярком свету листья бледнеют.', 'Ежегодно весной в неглубокую широкую плошку.', 'Абсолютно безопасно для питомцев.', 'Называют "молящимся растением" — на ночь поднимает и складывает листья.'),
('Орхидея Фаленопсис (Phalaenopsis)', 'Методом погружения горшка в воду на 15 минут, после того как корни станут серебристыми.', 'Яркий рассеянный свет. Прямое солнце вызывает сильные ожоги.', 'Раз в 2-3 года в специальный субстрат (кора сосны), предпочтительно в прозрачный горшок.', 'Не токсична.', 'Для цветения требуются суточные перепады температур (ночью прохладнее).'),
('Антуриум (Anthurium)', 'Поливать теплой водой, когда просохнет верхний слой. Очень любит высокую влажность воздуха.', 'Яркий, но строго рассеянный свет. Боится сквозняков.', 'Каждую весну в легкий воздухопроницаемый грунт (как для орхидей с добавлением торфа).', 'Сок ядовит, вызывает сильное раздражение слизистых оболочек.', 'Цветет круглый год при правильном уходе и подкормках.'),
('Сенполия (Фиалка узамбарская)', 'Полив через поддон или аккуратно по краю горшка, чтобы вода не попадала на листья.', 'Яркий рассеянный свет без прямых лучей. Идеальны восточные или западные окна.', 'Ежегодно в свежий легкий грунт. Горшок должен быть в 3 раза меньше диаметра розетки.', 'Безопасна для животных.', 'Листья нельзя опрыскивать из-за опушения (могут загнить).'),
('Калатея (Calathea)', 'Полив регулярный, теплой мягкой (отстоянной) водой. Грунт не должен пересыхать.', 'Полутень или рассеянный свет. Защищать от прямых лучей и сквозняков.', 'Раз в год весной в рыхлый, слабокислый грунт.', 'Не токсична.', 'Одно из самых капризных растений. Требует влажности воздуха не ниже 60%.');
